  }
  if (msgUpper.includes('DISCONNECT') && !msgUpper.includes('RPMDETECT')) {
    return { id, timestamp, rawTimestamp, type: 'CONNECTION', message: '연결 종료/해제', details: message };
  }
  if (msgUpper.includes('UNABLETOCONNECT')) {
    return { id, timestamp, rawTimestamp, type: 'CONNECTION', message: '연결 실패', details: message };
  }

  // 3. Protocol & Initialization (Critical for debugging connection)
  // Check for AT Commands: ATZ, ATSP, ATDP, ATDPN, ATE0, or Response 0100
  // Expanded regex to capture AT commands cleanly
  if (/(^|[\s>])(AT[A-Z0-9]+)([\r\n]|$)/i.test(message)) {
    const cmdMatch = message.match(/(AT[A-Z0-9]+)/i);
    const cmd = cmdMatch ? cmdMatch[1].toUpperCase() : 'AT Command';

    // Filter out common noise if needed, but for now capture all AT commands
    // We will filter in the UI
    return { id, timestamp, rawTimestamp, type: 'CONNECTION', message: `프로토콜 요청: ${cmd}`, details: message };
  }

  // Check for responses to AT commands (Simple 'OK' or 'ELM327' etc)
  // This is a heuristic: if the message is short and says "OK", it's likely a response
  if (/^OK[\r\n]*$/i.test(msgTrimmed) || /(^|[\s>])OK([\r\n]|$)/.test(message)) {
      return { id, timestamp, rawTimestamp, type: 'CONNECTION', message: '프로토콜 응답: OK', details: message };
  }

  // Check for specific OBD initialization responses that indicate protocol negotiation
  if (msgUpper.includes('SEARCHING...') || msgUpper.includes('BUS INIT')) {
    return { id, timestamp, rawTimestamp, type: 'CONNECTION', message: '프로토콜 초기화 중...', details: message };
  }

  // Check for Protocol Description response (usually a number or code like 'A6') - hard to detect reliably without context
  // but if we see 'AUTO' or ISO in response
  if (msgUpper.includes('AUTO,') || msgUpper.includes('ISO 15765')) {
     return { id, timestamp, rawTimestamp, type: 'CONNECTION', message: `프로토콜 감지: ${message}`, details: message };
  }

  return null;
};

// --- Connection Diagnosis Logic ---
// Removed unused 'metadata' parameter
const analyzeConnection = (logs: LogEntry[]): ConnectionDiagnosis => {
  const issues: string[] = [];
  let status: ConnectionDiagnosis['status'] = 'UNKNOWN';
  let csType: CsDiagnosisType = 'NONE';

  // Check for successful connection
  const connected = logs.some(l => l.message.includes('Connected state : 2') || l.message.includes('start scanner communication'));

  // Check for failures
  const busInitErrors = logs.filter(l => l.message.includes('BUSINIT') && l.message.includes('ERROR'));
  const unableToConnect = logs.filter(l => l.message.includes('UNABLETOCONNECT'));
  const canErrors = logs.filter(l => l.message.includes('CANERROR'));

  // CS SCENARIO 3: Wi-Fi Scanner Connection Issue
  // Detect if user is attempting to scan and WI-FI OBD is actually found
  // Condition 1: Scan was attempted (START SCAN, DISCOVERING, etc)
  const scanAttempted = logs.some(l => {
      const msg = l.message.toUpperCase();
      return msg.includes('START SCAN') || msg.includes('SCAN STARTED') || msg.includes('DISCOVERING');
  });

  // Condition 2: "WI FI OBD" (or similar) was explicitly discovered in the logs
  const wifiObdDiscovered = logs.some(l => {
      const msg = l.message.toUpperCase();
      // Look for discovery context
      const isDiscovery = msg.includes('DISCOVERED') || msg.includes('SCAN RESULT') || msg.includes('PERIPHERAL') || (msg.includes('SCAN') && msg.includes('NAME'));
      // Look for WI-FI related names: "WIFI OBD", "WI FI OBD", "WI-FI OBD"
      // We check if "WIFI" and "OBD" exist in the string to cover spacing variations
      const hasWifiName = (msg.includes('WIFI') || msg.includes('WI-FI') || msg.includes('WI FI')) && msg.includes('OBD');
      return isDiscovery && hasWifiName;
  });

  // Check if any target scanner was found in logs (General detection)
  const scannerFound = logs.some(l => {
    const msg = l.message.toLowerCase();

    // Check for discovery keywords
    const isDiscovery = 
        msg.includes('discovered') || 
        msg.includes('peripheral') || 
        msg.includes('scan result') || // Matches "SCAN Result"
        (msg.includes('scan') && msg.includes('name')) || 
        (msg.includes('scan') && msg.includes('address')); 

    // Check for target device names
    const hasTarget = 
        msg.includes('infocar') || 
        msg.includes('obdii') || 
        msg.includes('wifi obd') ||
        msg.includes('obdble'); // Added OBDBLE

    return isDiscovery && hasTarget;
  });

  // CS SCENARIO 4: HUD / Y-Cable Interference
  // Logic: Look for ATZ commands. 
  // A valid ATZ response is usually "ELM327 v1.5" or "OK".
  // Interference is characterized by the ATZ command returning RAW CAN FRAMES (e.g. 7E8..., 7E9...).
  // We strictly check for the presence of '7E8', '7E9', or '7EE' in the SAME log or the IMMEDIATE NEXT log.
  const hasHudInterference = logs.some((log, index) => {
      const msg = log.message.toUpperCase();

      if (msg.includes('ATZ')) {
          const CAN_IDS = ['7E8', '7E9', '7EE'];

          // 1. Check SAME LINE (e.g. "7DF, ATZ : 7E8...")
          if (CAN_IDS.some(id => msg.includes(id))) {
              return true;
          }

          // 2. Check IMMEDIATE NEXT LINE only
          // Avoid looking too far ahead to prevent flagging valid responses to subsequent commands.
          const nextLog = logs[index + 1];
          if (nextLog) {
              const nextMsg = nextLog.message.toUpperCase();
              // Ensure the next message actually looks like a CAN ID dump and NOT a new command or valid simple response
              if (CAN_IDS.some(id => nextMsg.includes(id))) {
                  return true;
              }
          }
      }
      return false;
  });

  // CS SCENARIO 2: NO DATA (Protocol mismatch)
  // Check if we have many NO DATA responses to standard PIDs (0100, 010C, 010D)
  const noDataLogs = logs.filter(l => {
      const msg = l.message.toUpperCase();
      // Check 0100 (Supported PIDs), 010C (RPM), 010D (Speed)
      // 0100 failure is critical (init failure)
      const isPid = msg.includes('01 0D') || msg.includes('01 0C') || msg.includes('01 00') || msg.includes('0100');

      // Check both "NODATA" and "NO DATA"
      const isNoData = msg.includes('NODATA') || msg.includes('NO DATA');

      return isPid && isNoData;
  });
  const noDataCount = noDataLogs.length;
  const hasInitNoData = noDataLogs.some(l => l.message.includes('01 00') || l.message.includes('0100'));

  // LOGIC TO DETERMINE CS TYPE
  if (hasHudInterference) {
      csType = 'HUD_INTERFERENCE';
      issues.push('ATZ 초기화 명령에 대해 표준(ELM327) 응답 대신 CAN 데이터(7E8/7E9...)가 감지되었습니다. (HUD, Y케이블 간섭 강력 의심)');
  } else if (scanAttempted && wifiObdDiscovered && !connected) {
      // Modified Logic: Only trigger if Scan was attempted AND Wifi OBD was actually found
      csType = 'WIFI_CONNECTION';
      issues.push('스캔 시도 중 "WI FI OBD" 기기가 검색되었으나 연결에 실패했습니다.');
  } else if (hasInitNoData || (connected && noDataCount > 5)) {
      // Modified: hasInitNoData alone is sufficient to trigger CS type even if 'connected' is false
      csType = 'NO_DATA_PROTOCOL';
      if (hasInitNoData) {
         issues.push('초기화 명령어(0100)에 대해 NO DATA 응답이 감지되었습니다. 차량과 프로토콜이 호환되지 않아 연결에 실패했습니다.');
      } else {
         issues.push(`주요 PID(RPM, 속도) 요청에 대해 NO DATA 응답이 ${noDataCount}회 발생했습니다. (프로토콜 호환성 문제)`);
      }
  } else if (!connected && (unableToConnect.length > 0 || !scannerFound)) {
      csType = 'GENERAL_CONNECTION';
  } else if (connected) {
      csType = 'SUCCESS';
  }

  if (connected) {
    status = 'SUCCESS';

    // Post-connection checks
    if (hasInitNoData || noDataCount > 5) {
      status = 'WARNING';
      // Issue pushed above in CS logic
    }
    if (busInitErrors.length > 0) {
      status = 'WARNING';
      issues.push('BUSINIT ERROR 발생: 차량과 통신 초기화 실패. 시동이 켜져 있는지 확인하거나 전압이 부족할 수 있습니다.');
    }
  } else {
    // Never connected
    if (logs.length > 0) status = 'FAILURE';

    // Scanner detection issue
    // For Wifi scenario, we rely on the specific check above
    if (!scannerFound && !wifiObdDiscovered) { 
      issues.push('인포카 스캐너가 검색되지 않았습니다. (검색된 기기 중 Infocar, OBDII, WIFI OBD, OBDBLE 이름이 없습니다)');
    }

    if (unableToConnect.length > 0) {
      issues.push('UNABLETOCONNECT: 블루투스 연결을 시도했으나 실패했습니다. 다른 기기와 이미 연결되어 있는지 확인하세요.');
    }
    if (busInitErrors.length > 0) {
      issues.push('BUSINIT ERROR: OBD 프로토콜 초기화 실패. 지원하지 않는 프로토콜이거나 시동 OFF 상태입니다.');
    }
    if (canErrors.length > 0) {
      issues.push('CAN ERROR: CAN 통신 오류. 배선 접촉 불량이나 OBD 단자 문제를 의심해볼 수 있습니다.');
    }
  }

  // Summary message
  let summary = '로그 데이터가 충분하지 않습니다.';
  if (status === 'SUCCESS') summary = '정상적으로 연결되었습니다.';
  if (status === 'WARNING') summary = '연결은 되었으나 통신 불안정이 감지됩니다.';
  if (status === 'FAILURE') {
    if (!scannerFound && !wifiObdDiscovered) {
        summary = '스캐너가 검색되지 않아 연결을 시도하지 못했습니다.';
    } else {
        summary = '차량 연결에 실패했습니다.';
    }
  }

  return { status, summary, issues, csType };
};

// --- Billing Log Parser ---
export const parseBillingLog = (content: string): BillingEntry[] => {
  const lines = content.split(/\r?\n/);
  const entries: BillingEntry[] = [];
  let id = 0;

  lines.forEach(line => {
    const match = line.match(REGEX_COMPACT);
    if (match) {
      const timestamp = match[1];
      const message = match[2];
      const logDate = parseDateString(timestamp, 'compact');

      entries.push({
        id: id++,
        timestamp: logDate,
        rawTimestamp: timestamp,
        message: message,
        isError: message.toLowerCase().includes('fail') || message.toLowerCase().includes('error')
      });
    }
  });

  return entries;
};

// --- Main Parser ---
export const parseLogFile = (content: string, fileName: string, billingContent?: string): ParsedData => {
  const lines = content.split(/\r?\n/);
  const logs: LogEntry[] = [];
  const lifecycleEvents: LifecycleEvent[] = [];

  const isIosFile = fileName.startsWith('log_');
  const detectedOS = isIosFile ? 'iOS (파일명 감지)' : 'Android (파일명 감지)';

  const metadata: SessionMetadata = {
    fileName: fileName,
    model: 'Unknown',
    userOS: detectedOS,
    appVersion: 'Unknown',
    carName: 'Unknown',
    userId: 'Unknown',
    logCount: 0,
    startTime: null,
    endTime: null,
    userInfo: {},
    carInfo: {},
    settingInfo: {},
    appInfo: {},
    extraInfo: {}
  };

  let idCounter = 0;
  let currentSection = 'extraInfo';

  lines.forEach((line) => {
    const trimmedLine = line.trim();
    if (!trimmedLine) return;

    // 1. Detect Sections
    const sectionMatch = trimmedLine.match(SECTION_HEADER);
    if (sectionMatch) {
      const sectionName = sectionMatch[1].toLowerCase();
      if (sectionName.includes('user')) currentSection = 'userInfo';
      else if (sectionName.includes('car')) currentSection = 'carInfo';
      else if (sectionName.includes('setting')) currentSection = 'settingInfo';
      else if (sectionName.includes('app')) currentSection = 'appInfo';
      else currentSection = 'extraInfo';
      return;
    }

    // 2. Parse Key-Value Pairs
    const kvMatch = trimmedLine.match(KEY_VALUE_PAIR);
    if (kvMatch && !trimmedLine.startsWith('[')) { 
      const key = kvMatch[1].trim();
      const value = kvMatch[2].trim();

      if (key === 'model' || key === 'Device Model') metadata.model = value;
      if (key === 'userOS') metadata.userOS = value;
      if (key === 'appVersion' || key === 'App version') metadata.appVersion = value;
      if (key === 'carName') metadata.carName = value;
      if (key === 'userId') metadata.userId = value;
      // Extract Country Code
      if (key.toLowerCase().includes('country')) metadata.countryCode = value;

      if (currentSection === 'userInfo') metadata.userInfo[key] = value;
      else if (currentSection === 'carInfo') metadata.carInfo[key] = value;
      else if (currentSection === 'settingInfo') metadata.settingInfo[key] = value;
      else if (currentSection === 'appInfo') metadata.appInfo[key] = value;
      else metadata.extraInfo[key] = value;
    }

    // 3. Parse Log Entries
    let timestamp: string | null = null;
    let message: string | null = null;
    let tsFormat: 'standard' | 'compact' = 'standard';

    const androidMatch = line.match(REGEX_ANDROID);
    const iosMatch = line.match(REGEX_IOS);
    const compactMatch = line.match(REGEX_COMPACT);

    if (androidMatch) {
      timestamp = androidMatch[1];
      message = androidMatch[2];
      tsFormat = 'standard';
    } else if (iosMatch) {
      timestamp = iosMatch[1];
      message = iosMatch[2];
      tsFormat = 'standard';
    } else if (compactMatch) {
      timestamp = compactMatch[1];
      message = compactMatch[2];
      tsFormat = 'compact';
    }

    if (timestamp && message) {
      const category = determineCategory(message);
      const logDate = parseDateString(timestamp, tsFormat);

      logs.push({
        id: idCounter,
        timestamp: logDate,
        rawTimestamp: timestamp,
        message: message,
        category: category,
        isError: category === LogCategory.ERROR,
        originalLine: line
      });

      const evt = identifyLifecycleEvent(message, logDate, timestamp, idCounter);
      if (evt) {
        lifecycleEvents.push(evt);
      }

      idCounter++;
    }
  });

  metadata.logCount = logs.length;
  if (logs.length > 0) {
    metadata.startTime = logs[0].timestamp;
    metadata.endTime = logs[logs.length - 1].timestamp;
  }

  // Parse billing logs if provided
  const billingLogs = billingContent ? parseBillingLog(billingContent) : [];

  // Analyze Connection
  // Updated call to match new signature (metadata removed)
  const diagnosis = analyzeConnection(logs);

  return { metadata, logs, lifecycleEvents, billingLogs, diagnosis, fileList: [] };
};

import { LogEntry, LogCategory, SessionMetadata, ParsedData, LifecycleEvent, BillingEntry, ConnectionDiagnosis, CsDiagnosisType } from '../types';

// Regex Patterns
// Unified regex to handle both Android (//) and iOS ( : ) separators, and both Full (YYYY-MM-DD...) and Short (HH:mm:ss...) timestamps
// Matches: [2024-12-10 14:20:30.123]//Msg or [14:20:30.123]//Msg or [2024-12-10 14:20:30:123] : Msg
const REGEX_FULL_TIMESTAMP = /^\[(\d{4}-\d{2}-\d{2}\s\d{2}:\d{2}:\d{2}[:\.]\d{3})\](?:\/\/|\s:\s)(.*)/;
const REGEX_SHORT_TIMESTAMP = /^\[(\d{2}:\d{2}:\d{2}[:\.]\d{3})\](?:\/\/|\s:\s)(.*)/;

const REGEX_COMPACT = /^\[(\d{14})\]\s:\s(.*)/; // For Billing
const SECTION_HEADER = /^={5}\s(.*?)\s={5}/;
const KEY_VALUE_PAIR = /^([^:]+)\s:\s(.*)/;

// Extract date from filename (YYYY-MM-DD pattern)
const getDateFromFileName = (fileName: string): Date => {
  try {
    const match = fileName.match(/(\d{4})-(\d{2})-(\d{2})/);
    if (match) {
      return new Date(parseInt(match[1]), parseInt(match[2]) - 1, parseInt(match[3]));
    }
  } catch (e) {
    // ignore
  }
  return new Date(); // Fallback to today
};

// Helper to normalize timestamp string to Date object
const parseLogDate = (timestampStr: string, baseDate: Date): Date => {
  try {
    // Case 1: Full Timestamp "2024-12-10 14:20:30.123" (or :123)
    if (timestampStr.length > 15) {
      const cleanTs = timestampStr.replace(/:(\d{3})$/, '.$1').replace(' ', 'T');
      return new Date(cleanTs);
    }

    // Case 2: Short Timestamp "14:20:30.123" (or :123)
    // Combine with baseDate
    const timeParts = timestampStr.split(/[:\.]/); // HH, mm, ss, ms
    if (timeParts.length >= 4) {
      const d = new Date(baseDate);
      d.setHours(parseInt(timeParts[0]));
      d.setMinutes(parseInt(timeParts[1]));
      d.setSeconds(parseInt(timeParts[2]));
      d.setMilliseconds(parseInt(timeParts[3]));
      return d;
    }

    return new Date();
  } catch (e) {
    return new Date();
  }
};

const parseBillingDate = (compactStr: string): Date => {
  try {
     // YYYYMMDDHHmmss
     const year = parseInt(compactStr.substring(0, 4));
     const month = parseInt(compactStr.substring(4, 6)) - 1;
     const day = parseInt(compactStr.substring(6, 8));
     const hour = parseInt(compactStr.substring(8, 10));
     const min = parseInt(compactStr.substring(10, 12));
     const sec = parseInt(compactStr.substring(12, 14));
     return new Date(year, month, day, hour, min, sec);
  } catch(e) {
    return new Date();
  }
}

const determineCategory = (message: string): LogCategory => {
  const msgUpper = message.toUpperCase();

  if (
    msgUpper.includes('FAIL') || 
    msgUpper.includes('UNABLETOCONNECT') || 
    msgUpper.includes('EXCEPTION') || 
    msgUpper.includes('ERROR') ||
    msgUpper.includes('NODATA') ||
    msgUpper.includes('NO DATA') ||
    msgUpper.includes('LV RESET') || // Low Voltage Reset
    msgUpper.includes('BUFFER FULL') ||
    msgUpper.includes('STOPPED') ||
    msgUpper.includes(' 204 ')
  ) {
    return LogCategory.ERROR;
  }

  if (
    msgUpper.includes('7DF') || 
    msgUpper.includes('ATZ') || 
    msgUpper.includes('ATSP') || 
    /^[0-9A-F]{2,}\s?>/.test(message) || 
    msgUpper.includes('PID')
  ) {
    return LogCategory.OBD;
  }

  if (
    msgUpper.includes('CONNECT') || 
    msgUpper.includes('BLE') || 
    msgUpper.includes('SCANNER') || 
    msgUpper.includes('PERIPHERAL') || 
    msgUpper.includes('CHARACTERISTIC') || 
    msgUpper.includes('SCAN RESULT') ||
    msgUpper.includes('OBDBLE')
  ) {
    return LogCategory.BLUETOOTH;
  }

  if (
    msgUpper.includes('SETSCREEN') || 
    msgUpper.includes('MOVE TO') ||
    msgUpper.includes('TOAST') || 
    msgUpper.includes('FRAGMENT') || 
    msgUpper.includes('ACTIVITY') || 
    msgUpper.includes('VIEW') ||
    msgUpper.includes('SCENE')
  ) {
    return LogCategory.UI;
  }

  return LogCategory.INFO;
};

// Check for significant lifecycle events
const identifyLifecycleEvent = (message: string, timestamp: Date, rawTimestamp: string, id: number): LifecycleEvent | null => {
  const msgUpper = message.toUpperCase();
  const msgTrimmed = message.trim();

  // 1. Screen Transitions
  if (msgUpper.includes('SETSCREEN')) {
    const screenName = message.replace(/.*setScreen\s+/, '').trim();
    return { id, timestamp, rawTimestamp, type: 'SCREEN', message: `화면 이동: ${screenName}`, details: message };
  }

  if (msgUpper.includes('MOVE TO')) {
    let rawName = message;
    const bracketMatch = message.match(/<([^>]+)>/);
    if (bracketMatch) {
        rawName = bracketMatch[1].split(':')[0].trim();
    } else {
        const match = message.match(/move to\s+(.*)/i);
        if (match) {
            rawName = match[1].trim();
        }
    }
    const shortName = rawName.split('.').pop() || rawName;
    const finalName = shortName.replace('ViewController', '').trim();

    return { id, timestamp, rawTimestamp, type: 'SCREEN', message: `화면 이동: ${finalName}`, details: message };
  }

  if (msgUpper.includes('SCENEDIDBECOMEACTIVE')) {
     return { id, timestamp, rawTimestamp, type: 'APP_STATE', message: '앱 활성화 (Active)', details: message };
  }
  if (msgUpper.includes('SCENEDIDENTERBACKGROUND')) {
     return { id, timestamp, rawTimestamp, type: 'APP_STATE', message: '앱 백그라운드 전환', details: message };
  }

  // 2. Connection States
  if (msgUpper.includes('CONNECTED STATE : 2') || msgUpper.includes('START SCANNER COMMUNICATION')) {
    return { id, timestamp, rawTimestamp, type: 'CONNECTION', message: '스캐너 연결 성공', details: message };
  }
  if (msgUpper.includes('DISCONNECT') && !msgUpper.includes('RPMDETECT')) {
    return { id, timestamp, rawTimestamp, type: 'CONNECTION', message: '연결 종료/해제', details: message };
  }
  if (msgUpper.includes('UNABLETOCONNECT')) {
    return { id, timestamp, rawTimestamp, type: 'CONNECTION', message: '연결 실패', details: message };
  }
  if (msgUpper.includes('LV RESET')) {
    return { id, timestamp, rawTimestamp, type: 'CONNECTION', message: '⚠️ LV RESET (저전압 재부팅)', details: '차량 전압 부족으로 인한 모듈 리셋 감지' };
  }

  // 3. Protocol & Initialization
  // Expanded regex to capture AT commands cleanly
  if (/(^|[\s>])(AT[A-Z0-9]+)([\r\n]|$)/i.test(message)) {
    const cmdMatch = message.match(/(AT[A-Z0-9]+)/i);
    const cmd = cmdMatch ? cmdMatch[1].toUpperCase() : 'AT Command';
    return { id, timestamp, rawTimestamp, type: 'CONNECTION', message: `프로토콜 요청: ${cmd}`, details: message };
  }

  if (/^OK[\r\n]*$/i.test(msgTrimmed) || /(^|[\s>])OK([\r\n]|$)/.test(message)) {
      return { id, timestamp, rawTimestamp, type: 'CONNECTION', message: '프로토콜 응답: OK', details: message };
  }

  if (msgUpper.includes('SEARCHING...') || msgUpper.includes('BUS INIT')) {
    return { id, timestamp, rawTimestamp, type: 'CONNECTION', message: '프로토콜 초기화 중...', details: message };
  }

  if (msgUpper.includes('AUTO,') || msgUpper.includes('ISO 15765')) {
     return { id, timestamp, rawTimestamp, type: 'CONNECTION', message: `프로토콜 감지: ${message}`, details: message };
  }

  return null;
};

// --- Connection Diagnosis Logic ---
const analyzeConnection = (logs: LogEntry[]): ConnectionDiagnosis => {
  const issues: string[] = [];
  let status: ConnectionDiagnosis['status'] = 'UNKNOWN';
  let csType: CsDiagnosisType = 'NONE';

  // Check for successful connection
  const connected = logs.some(l => l.message.includes('Connected state : 2') || l.message.includes('start scanner communication'));

  // Check for failures
  const busInitErrors = logs.filter(l => l.message.includes('BUSINIT') && l.message.includes('ERROR'));
  const unableToConnect = logs.filter(l => l.message.includes('UNABLETOCONNECT'));
  const canErrors = logs.filter(l => l.message.includes('CANERROR'));
  const lvResetErrors = logs.filter(l => l.message.includes('LV RESET'));

  // CS SCENARIO 3: Wi-Fi Scanner Connection Issue
  const scanAttempted = logs.some(l => {
      const msg = l.message.toUpperCase();
      return msg.includes('START SCAN') || msg.includes('SCAN STARTED') || msg.includes('DISCOVERING');
  });

  const wifiObdDiscovered = logs.some(l => {
      const msg = l.message.toUpperCase();
      const isDiscovery = msg.includes('DISCOVERED') || msg.includes('SCAN RESULT') || msg.includes('PERIPHERAL') || (msg.includes('SCAN') && msg.includes('NAME'));
      const hasWifiName = (msg.includes('WIFI') || msg.includes('WI-FI') || msg.includes('WI FI')) && msg.includes('OBD');
      return isDiscovery && hasWifiName;
  });

  const scannerFound = logs.some(l => {
    const msg = l.message.toLowerCase();
    const isDiscovery = 
        msg.includes('discovered') || 
        msg.includes('peripheral') || 
        msg.includes('scan result') || 
        (msg.includes('scan') && msg.includes('name')) || 
        (msg.includes('scan') && msg.includes('address')); 

    const hasTarget = 
        msg.includes('infocar') || 
        msg.includes('obdii') || 
        msg.includes('wifi obd') ||
        msg.includes('obdble'); 

    return isDiscovery && hasTarget;
  });

  // CS SCENARIO 4: HUD / Y-Cable Interference
  const hasHudInterference = logs.some((log, index) => {
      const msg = log.message.toUpperCase();

      if (msg.includes('ATZ')) {
          const CAN_IDS = ['7E8', '7E9', '7EE'];
          if (CAN_IDS.some(id => msg.includes(id))) return true;
          const nextLog = logs[index + 1];
          if (nextLog) {
              const nextMsg = nextLog.message.toUpperCase();
              if (CAN_IDS.some(id => nextMsg.includes(id))) return true;
          }
      }
      return false;
  });

  // CS SCENARIO 2: NO DATA (Protocol mismatch)
  const noDataLogs = logs.filter(l => {
      const msg = l.message.toUpperCase();
      // Check 0100, 010C, 010D
      const isPid = msg.includes('01 0D') || msg.includes('01 0C') || msg.includes('01 00') || msg.includes('0100');
      // Check both "NODATA" and "NO DATA"
      const isNoData = msg.includes('NODATA') || msg.includes('NO DATA');
      return isPid && isNoData;
  });
  const noDataCount = noDataLogs.length;
  const hasInitNoData = noDataLogs.some(l => l.message.includes('01 00') || l.message.includes('0100'));

  // LOGIC TO DETERMINE CS TYPE
  if (hasHudInterference) {
      csType = 'HUD_INTERFERENCE';
      issues.push('ATZ 초기화 명령에 대해 표준(ELM327) 응답 대신 CAN 데이터(7E8/7E9...)가 감지되었습니다. (HUD, Y케이블 간섭 강력 의심)');
  } else if (scanAttempted && wifiObdDiscovered && !connected) {
      csType = 'WIFI_CONNECTION';
      issues.push('스캔 시도 중 "WI FI OBD" 기기가 검색되었으나 연결에 실패했습니다.');
  } else if (hasInitNoData || (connected && noDataCount > 5)) {
      csType = 'NO_DATA_PROTOCOL';
      if (hasInitNoData) {
         issues.push('초기화 명령어(0100)에 대해 NO DATA 응답이 감지되었습니다. 차량과 프로토콜이 호환되지 않아 연결에 실패했습니다.');
      } else {
         issues.push(`주요 PID(RPM, 속도) 요청에 대해 NO DATA 응답이 ${noDataCount}회 발생했습니다. (프로토콜 호환성 문제)`);
      }
  } else if (!connected && (unableToConnect.length > 0 || !scannerFound)) {
      csType = 'GENERAL_CONNECTION';
  } else if (connected) {
      csType = 'SUCCESS';
  }

  if (connected) {
    status = 'SUCCESS';

    if (hasInitNoData || noDataCount > 5) {
      status = 'WARNING';
    }
    if (busInitErrors.length > 0) {
      status = 'WARNING';
      issues.push('BUSINIT ERROR 발생: 차량과 통신 초기화 실패. 시동이 켜져 있는지 확인하거나 전압이 부족할 수 있습니다.');
    }
    if (lvResetErrors.length > 0) {
      status = 'WARNING';
      issues.push('LV RESET 발생: 저전압으로 인한 모듈 리셋이 감지되었습니다. 차량 배터리 상태 확인이 필요합니다.');
    }
  } else {
    // Never connected
    if (logs.length > 0) status = 'FAILURE';

    if (!scannerFound && !wifiObdDiscovered) { 
      issues.push('인포카 스캐너가 검색되지 않았습니다. (검색된 기기 중 Infocar, OBDII, WIFI OBD, OBDBLE 이름이 없습니다)');
    }

    if (unableToConnect.length > 0) {
      issues.push('UNABLETOCONNECT: 블루투스 연결을 시도했으나 실패했습니다. 다른 기기와 이미 연결되어 있는지 확인하세요.');
    }
    if (busInitErrors.length > 0) {
      issues.push('BUSINIT ERROR: OBD 프로토콜 초기화 실패. 지원하지 않는 프로토콜이거나 시동 OFF 상태입니다.');
    }
    if (canErrors.length > 0) {
      issues.push('CAN ERROR: CAN 통신 오류. 배선 접촉 불량이나 OBD 단자 문제를 의심해볼 수 있습니다.');
    }
    if (lvResetErrors.length > 0) {
        issues.push('LV RESET: 저전압 리셋 발생. 전원 공급이 불안정합니다.');
    }
  }

  // Summary message
  let summary = '로그 데이터가 충분하지 않습니다.';
  if (status === 'SUCCESS') summary = '정상적으로 연결되었습니다.';
  if (status === 'WARNING') summary = '연결은 되었으나 통신 불안정이 감지됩니다.';
  if (status === 'FAILURE') {
    if (!scannerFound && !wifiObdDiscovered) {
        summary = '스캐너가 검색되지 않아 연결을 시도하지 못했습니다.';
    } else {
        summary = '차량 연결에 실패했습니다.';
    }
  }

  return { status, summary, issues, csType };
};

// --- Billing Log Parser ---
export const parseBillingLog = (content: string): BillingEntry[] => {
  const lines = content.split(/\r?\n/);
  const entries: BillingEntry[] = [];
  let id = 0;

  lines.forEach(line => {
    const match = line.match(REGEX_COMPACT);
    if (match) {
      const timestamp = match[1];
      const message = match[2];
      const logDate = parseBillingDate(timestamp);

      entries.push({
        id: id++,
        timestamp: logDate,
        rawTimestamp: timestamp,
        message: message,
        isError: message.toLowerCase().includes('fail') || message.toLowerCase().includes('error') || message.includes('USER_CANCELED') || message.includes('SERVICE_UNAVAILABLE')
      });
    }
  });

  return entries;
};

// --- Main Parser ---
export const parseLogFile = (content: string, fileName: string, billingContent?: string): ParsedData => {
  const lines = content.split(/\r?\n/);
  const logs: LogEntry[] = [];
  const lifecycleEvents: LifecycleEvent[] = [];

  // Base date for short timestamps
  const baseDate = getDateFromFileName(fileName);

  const isIosFile = fileName.startsWith('log_');
  const detectedOS = isIosFile ? 'iOS (파일명 감지)' : 'Android (파일명 감지)';

  const metadata: SessionMetadata = {
    fileName: fileName,
    model: 'Unknown',
    userOS: detectedOS,
    appVersion: 'Unknown',
    carName: 'Unknown',
    userId: 'Unknown',
    logCount: 0,
    startTime: null,
    endTime: null,
    userInfo: {},
    carInfo: {},
    settingInfo: {},
    appInfo: {},
    extraInfo: {}
  };

  let idCounter = 0;
  let currentSection = 'extraInfo';

  lines.forEach((line) => {
    const trimmedLine = line.trim();
    if (!trimmedLine) return;

    // 1. Detect Sections
    const sectionMatch = trimmedLine.match(SECTION_HEADER);
    if (sectionMatch) {
      const sectionName = sectionMatch[1].toLowerCase();
      if (sectionName.includes('user')) currentSection = 'userInfo';
      else if (sectionName.includes('car')) currentSection = 'carInfo';
      else if (sectionName.includes('setting')) currentSection = 'settingInfo';
      else if (sectionName.includes('app')) currentSection = 'appInfo';
      else currentSection = 'extraInfo'; // Protocol info goes here
      return;
    }

    // 2. Parse Key-Value Pairs
    const kvMatch = trimmedLine.match(KEY_VALUE_PAIR);
    if (kvMatch && !trimmedLine.startsWith('[')) { 
      const key = kvMatch[1].trim();
      const value = kvMatch[2].trim();

      if (key === 'model' || key === 'Device Model') metadata.model = value;
      if (key === 'userOS') metadata.userOS = value;
      if (key === 'appVersion' || key === 'App version') metadata.appVersion = value;
      if (key === 'carName') metadata.carName = value;
      if (key === 'userId') metadata.userId = value;
      if (key.toLowerCase().includes('country')) metadata.countryCode = value;

      if (currentSection === 'userInfo') metadata.userInfo[key] = value;
      else if (currentSection === 'carInfo') metadata.carInfo[key] = value;
      else if (currentSection === 'settingInfo') metadata.settingInfo[key] = value;
      else if (currentSection === 'appInfo') metadata.appInfo[key] = value;
      else metadata.extraInfo[key] = value;
    }

    // 3. Parse Log Entries
    let timestampStr: string | null = null;
    let message: string | null = null;

    const fullMatch = line.match(REGEX_FULL_TIMESTAMP);
    const shortMatch = line.match(REGEX_SHORT_TIMESTAMP);
    const compactMatch = line.match(REGEX_COMPACT);

    if (fullMatch) {
      timestampStr = fullMatch[1];
      message = fullMatch[2];
    } else if (shortMatch) {
      timestampStr = shortMatch[1];
      message = shortMatch[2];
    } else if (compactMatch) {
      // Typically billing logs, but safe to handle
      timestampStr = compactMatch[1];
      message = compactMatch[2];
    }

    if (timestampStr && message) {
      let logDate: Date;
      if (compactMatch) {
        logDate = parseBillingDate(timestampStr);
      } else {
        logDate = parseLogDate(timestampStr, baseDate);
      }

      const category = determineCategory(message);

      logs.push({
        id: idCounter,
        timestamp: logDate,
        rawTimestamp: timestampStr,
        message: message,
        category: category,
        isError: category === LogCategory.ERROR,
        originalLine: line
      });

      const evt = identifyLifecycleEvent(message, logDate, timestampStr, idCounter);
      if (evt) {
        lifecycleEvents.push(evt);
      }

      idCounter++;
    }
  });

  metadata.logCount = logs.length;
  if (logs.length > 0) {
    metadata.startTime = logs[0].timestamp;
    metadata.endTime = logs[logs.length - 1].timestamp;
  }

  const billingLogs = billingContent ? parseBillingLog(billingContent) : [];
  const diagnosis = analyzeConnection(logs);

  return { metadata, logs, lifecycleEvents, billingLogs, diagnosis, fileList: [] };
};

import React, { useState, useMemo, useRef } from 'react';
import { LogEntry, LogCategory } from '../types';
import { FileCode, Copy, Check, Play, Loader2, Clock, AlertCircle, FileJson } from 'lucide-react';

interface ResponseSimulatorProps {
  logs: LogEntry[];
  startTime: Date | null;
  endTime: Date | null;
}

interface CommandGroup {
  command: string;
  responses: string[];
}

// Format Date for display
const formatDisplayTime = (date: Date) => {
  return date.toLocaleString('ko-KR', {
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hour12: false
  });
};

const formatDuration = (ms: number) => {
  const seconds = Math.floor(ms / 1000);
  if (seconds < 60) return `${seconds}초`;
  const minutes = Math.floor(seconds / 60);
  return `${minutes}분 ${seconds % 60}초`;
};

export const ResponseSimulator: React.FC<ResponseSimulatorProps> = ({ logs, startTime, endTime }) => {
  const [range, setRange] = useState<[number, number]>([0, 100]); // Percentage 0-100
  const [results, setResults] = useState<CommandGroup[]>([]);
  const [generatedJson, setGeneratedJson] = useState<string>('');
  const [isCopied, setIsCopied] = useState(false);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [hasAnalyzed, setHasAnalyzed] = useState(false);

  const sliderRef = useRef<HTMLDivElement>(null);

  // 1. Calculate Session Data & Active Ranges
  const { minTime, maxTime, activeRanges } = useMemo(() => {
    if (!logs.length || !startTime || !endTime) {
      return { minTime: 0, maxTime: 0, activeRanges: [] };
    }

    const originalMin = startTime.getTime();
    const originalMax = endTime.getTime();

    // Store ranges in absolute timestamps first
    const absoluteRanges: { start: number; end: number }[] = [];
    let detectedStartTime: number | null = null;

    // State Machine for detection
    // States: IDLE -> 0100_OK -> SESSION_ACTIVE -> IDLE
    let state: 'IDLE' | '0100_OK' | 'SESSION_ACTIVE' = 'IDLE';
    let sessionStartTime = 0;

    for (let i = 0; i < logs.length; i++) {
        const log = logs[i];
        const msg = log.message.toUpperCase();

        // Check for Disconnect/Finish first to close any active session
        if (msg.includes('CONNECTED_FINISH') || msg.includes('DISCONNECT') || msg.includes('UNABLETOCONNECT')) {
            if (state === 'SESSION_ACTIVE') {
                // Close session
                absoluteRanges.push({
                    start: sessionStartTime,
                    end: log.timestamp.getTime()
                });
            }
            state = 'IDLE';
            continue;
        }

        if (state === 'IDLE') {
            // Check for 01 00 (Support PIDs) Response
            // Pattern: "01 00", "0100" in command, response usually "41 00 ..." or valid data
            if ((msg.includes('01 00') || msg.includes('0100')) && !log.isError && !msg.includes('NODATA')) {
                state = '0100_OK';
                // If this is the FIRST detection, set it as the timeline start
                if (detectedStartTime === null) {
                    detectedStartTime = log.timestamp.getTime();
                }
            }
        } else if (state === '0100_OK') {
            // Look for 01 0D (Speed)
            if ((msg.includes('01 0D') || msg.includes('010D')) && !log.isError && !msg.includes('NODATA')) {
                state = 'SESSION_ACTIVE';
                sessionStartTime = log.timestamp.getTime();
            }
        }
    }

    // If still active at the end, close it at maxTime
    if (state === 'SESSION_ACTIVE') {
        absoluteRanges.push({
            start: sessionStartTime,
            end: originalMax
        });
    }

    // Determine the effective start time (Trim lead time)
    // If we found a start time (0100), use it. Otherwise fallback to file start.
    const effectiveMin = detectedStartTime !== null ? detectedStartTime : originalMin;
    const duration = originalMax - effectiveMin;

    // Convert absolute ranges to percentages relative to effectiveMin
    // Filter out ranges that ended before effectiveMin
    const ranges = absoluteRanges
        .filter(r => r.end > effectiveMin)
        .map(r => {
            const start = Math.max(r.start, effectiveMin);
            return {
                startPercent: ((start - effectiveMin) / duration) * 100,
                widthPercent: ((r.end - start) / duration) * 100
            };
        });

    return { minTime: effectiveMin, maxTime: originalMax, activeRanges: ranges };
  }, [logs, startTime, endTime]);

  // Derived selected times
  const selectedStartTime = useMemo(() => new Date(minTime + (maxTime - minTime) * (range[0] / 100)), [minTime, maxTime, range]);
  const selectedEndTime = useMemo(() => new Date(minTime + (maxTime - minTime) * (range[1] / 100)), [minTime, maxTime, range]);
  const selectionDuration = selectedEndTime.getTime() - selectedStartTime.getTime();

  // 2. Drag Logic
  const handleMouseDown = (index: 0 | 1) => (e: React.MouseEvent) => {
    e.preventDefault();
    const slider = sliderRef.current;
    if (!slider) return;

    const startX = e.clientX;
    const startPercent = range[index];
    const { width } = slider.getBoundingClientRect();

    const onMouseMove = (moveEvent: MouseEvent) => {
      const deltaX = moveEvent.clientX - startX;
      const deltaPercent = (deltaX / width) * 100;
      let newPercent = startPercent + deltaPercent;

      // Clamp
      newPercent = Math.max(0, Math.min(100, newPercent));

      setRange(prev => {
        const newRange = [...prev] as [number, number];
        newRange[index] = newPercent;

        // Prevent crossing
        if (index === 0 && newRange[0] > newRange[1]) newRange[0] = newRange[1];
        if (index === 1 && newRange[1] < newRange[0]) newRange[1] = newRange[0];

        return newRange;
      });
    };

    const onMouseUp = () => {
      window.removeEventListener('mousemove', onMouseMove);
      window.removeEventListener('mouseup', onMouseUp);
    };

    window.addEventListener('mousemove', onMouseMove);
    window.addEventListener('mouseup', onMouseUp);
  };

  const generateJson = (groups: CommandGroup[]) => {
    const obj: Record<string, string[]> = {};
    groups.forEach(g => {
        obj[g.command] = g.responses;
    });
    return JSON.stringify(obj, null, 2);
  };

  const handleAnalyze = () => {
    if (!selectedStartTime || !selectedEndTime) return;

    setIsAnalyzing(true);
    setHasAnalyzed(false);

    setTimeout(() => {
      const filteredLogs = logs.filter(log => {
        return log.timestamp >= selectedStartTime && 
               log.timestamp <= selectedEndTime && 
               (log.category === LogCategory.OBD || log.category === LogCategory.BLUETOOTH);
      });

      const groups: Record<string, string[]> = {};
      // Regex Update: Support optional generic prefix before command (e.g., "ECU, ", "7DF, ")
      // Format: [Prefix, ] Command : Response [ , delay ...]
      const regex = /(?:[^,]+,\s*)?([0-9A-F\s]{2,})\s:\s(.*?)(?=, delay|$)/;

      filteredLogs.forEach(log => {
        const msg = log.message;
        const match = msg.match(regex);

        if (match) {
          const cmd = match[1].trim();
          const resp = match[2].trim();

          if (resp && !resp.includes('NO DATA') && !resp.includes('ERROR') && !resp.includes('NODATA')) {
             if (!groups[cmd]) groups[cmd] = [];
             groups[cmd].push(resp);
          }
        }
      });

      const resultArray = Object.keys(groups).sort().map(cmd => ({
        command: cmd,
        responses: groups[cmd]
      }));

      setResults(resultArray);
      setGeneratedJson(generateJson(resultArray));
      setIsAnalyzing(false);
      setHasAnalyzed(true);
    }, 100);
  };

  const handleCopyCode = () => {
    navigator.clipboard.writeText(generatedJson);
    setIsCopied(true);
    setTimeout(() => setIsCopied(false), 2000);
  };

  if (!startTime || !endTime) return null;

  return (
    <div className="space-y-6 pb-20">
      <div className="bg-white p-6 rounded-lg border border-slate-200 shadow-sm">
        <div className="flex items-start gap-4 mb-8">
          <div className="p-2 bg-indigo-50 rounded-lg">
            <FileCode className="w-6 h-6 text-indigo-600" />
          </div>
          <div className="flex-1">
            <h2 className="text-lg font-bold text-slate-900">OBD 응답 데이터 추출</h2>
            <p className="text-sm text-slate-500 mt-1">
              선택한 구간의 OBD 응답 값을 JSON 형식으로 추출합니다. 추출된 파일은 <code>assets/obd_mock_data.json</code>으로 저장하여 로더 클래스에서 사용하세요.
            </p>
          </div>
        </div>

        {/* Custom Range Slider Area */}
        <div className="flex flex-col md:flex-row gap-8 px-2 pb-4">

          {/* Left: Slider */}
          <div className="flex-1 pt-6">
            <div className="flex justify-between text-xs font-semibold text-slate-400 mb-2">
               <span title="첫 통신 시작 시점 (Lead Time 제거됨)">{formatDisplayTime(new Date(minTime))}</span>
               <span>{formatDisplayTime(new Date(maxTime))}</span>
            </div>

            <div className="relative h-6 select-none flex items-center" ref={sliderRef}>
              <div className="absolute w-full h-4 bg-slate-200 rounded-full overflow-hidden">
                 {activeRanges.map((r, i) => (
                   <div 
                      key={i}
                      className="absolute h-full bg-green-400 opacity-80"
                      style={{ left: `${r.startPercent}%`, width: `${r.widthPercent}%` }}
                   />
                 ))}
              </div>

              <div 
                className="absolute h-4 bg-indigo-600 opacity-20 pointer-events-none rounded-sm"
                style={{ left: `${range[0]}%`, width: `${range[1] - range[0]}%` }}
              />

              {/* Handle 1 */}
              <div 
                className="absolute top-[-20px] w-0 h-0 border-l-[8px] border-l-transparent border-r-[8px] border-r-transparent border-t-[12px] border-t-indigo-600 cursor-ew-resize z-10 hover:scale-110 transition-transform drop-shadow-md"
                style={{ left: `calc(${range[0]}% - 8px)` }}
                onMouseDown={handleMouseDown(0)}
              >
                  <div className="absolute -top-[24px] -left-[12px] w-6 h-6 bg-indigo-600 rounded-full flex items-center justify-center text-[10px] text-white font-bold shadow-sm">S</div>
              </div>

              {/* Handle 2 */}
              <div 
                className="absolute top-[-20px] w-0 h-0 border-l-[8px] border-l-transparent border-r-[8px] border-r-transparent border-t-[12px] border-t-indigo-600 cursor-ew-resize z-10 hover:scale-110 transition-transform drop-shadow-md"
                style={{ left: `calc(${range[1]}% - 8px)` }}
                onMouseDown={handleMouseDown(1)}
              >
                  <div className="absolute -top-[24px] -left-[12px] w-6 h-6 bg-indigo-600 rounded-full flex items-center justify-center text-[10px] text-white font-bold shadow-sm">E</div>
              </div>
            </div>
          </div>

          {/* Right: Info Panel */}
          <div className="w-full md:w-64 shrink-0 bg-slate-50 rounded-lg p-4 border border-slate-200 flex flex-col justify-center space-y-3">
             <div className="flex items-center gap-2 text-indigo-900 font-bold border-b border-slate-200 pb-2 mb-1">
                <Clock className="w-4 h-4" />
                <span>선택된 구간</span>
             </div>
             <div>
                <span className="text-xs text-slate-500 block uppercase">시작 (Start)</span>
                <span className="font-mono text-sm font-semibold text-slate-700">{formatDisplayTime(selectedStartTime)}</span>
             </div>
             <div>
                <span className="text-xs text-slate-500 block uppercase">종료 (End)</span>
                <span className="font-mono text-sm font-semibold text-slate-700">{formatDisplayTime(selectedEndTime)}</span>
             </div>
             <div className="pt-2 border-t border-slate-200">
                <span className="text-xs text-slate-500 block uppercase">기간 (Duration)</span>
                <span className="font-mono text-sm font-bold text-indigo-600">{formatDuration(selectionDuration)}</span>
             </div>
          </div>
        </div>

        {/* Analyze Action */}
        <div className="flex justify-center mt-6">
            <button 
              onClick={handleAnalyze}
              disabled={isAnalyzing}
              className={`flex items-center justify-center gap-2 px-8 py-3 rounded-full font-bold shadow-lg transition-all ${
                isAnalyzing 
                ? 'bg-slate-300 text-slate-500 cursor-not-allowed' 
                : 'bg-indigo-600 hover:bg-indigo-700 text-white shadow-indigo-200 hover:-translate-y-0.5'
              }`}
            >
              {isAnalyzing ? (
                <>
                  <Loader2 className="w-5 h-5 animate-spin" />
                  분석 및 추출 중...
                </>
              ) : (
                <>
                  <Play className="w-4 h-4" />
                  데이터 추출하기 (JSON)
                </>
              )}
            </button>
        </div>
      </div>

      {/* Results */}
      {results.length > 0 ? (
        <div className="bg-slate-800 rounded-lg shadow-lg overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-500">
           {/* Toolbar */}
           <div className="bg-slate-900 px-4 py-3 flex items-center justify-between border-b border-slate-700">
              <div className="flex items-center gap-2">
                 <FileJson className="w-4 h-4 text-yellow-400" />
