             <div className="flex items-center gap-2 px-4 py-2 bg-slate-100 text-slate-600 rounded-md text-sm font-medium">
                <FileText className="w-4 h-4" /> 텍스트
             </div>
             <div className="flex items-center gap-2 px-4 py-2 bg-slate-100 text-slate-600 rounded-md text-sm font-medium">
                <FileArchive className="w-4 h-4" /> ZIP 압축
             </div>
          </div>
        </div>
        <input 
          id="fileInput" 
