import { ParsedData, LogFileContext } from './types';

function App() {
  const [data, setData] = useState<ParsedData | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState('로그 분석 중...');

  // Store all extracted logs to allow switching without re-reading zip
  const [cachedMainLogs, setCachedMainLogs] = useState<LogFileContext[]>([]);
  const [cachedBillingContent, setCachedBillingContent] = useState<string>('');

  const processContent = (mainContent: string, fileName: string, billingContent: string, availableFiles: LogFileContext[]) => {
    try {
      const parsed = parseLogFile(mainContent, fileName, billingContent);
      // Attach the list of available files to the parsed data so the Dashboard can show the selector
      parsed.fileList = availableFiles;
      setData(parsed);
    } catch (error) {
      console.error("Failed to parse log file", error);
      alert("로그 파일을 분석하는 데 실패했습니다.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleFileSelect = (fileName: string) => {
    const selectedFile = cachedMainLogs.find(f => f.fileName === fileName);
    if (selectedFile) {
      setIsLoading(true);
      setLoadingMessage(`${fileName} 분석 중...`);
      // Use setTimeout to allow UI to update
      setTimeout(() => {
        processContent(selectedFile.content, selectedFile.fileName, cachedBillingContent, cachedMainLogs);
      }, 50);
    }
  };

  const handleFile = async (file: File) => {
    setIsLoading(true);
    setLoadingMessage('파일 읽는 중...');

    // Small delay to render loading state
    await new Promise(resolve => setTimeout(resolve, 100));

    if (file.name.endsWith('.zip')) {
      setLoadingMessage('ZIP 압축 해제 및 파일 검색 중...');
      try {
        const zip = await JSZip.loadAsync(file);

        const mainLogs: LogFileContext[] = [];
        let billingContents: string[] = [];

        // Traverse ZIP
        const promises: Promise<void>[] = [];

        zip.forEach((relativePath, zipEntry) => {
            if (zipEntry.dir) return;
            const name = relativePath; // Keep full path to distinguish logic
            const lowerName = name.toLowerCase();

            // 1. Billing Logs (Aggregate all)
            // iOS: purchase_log_*.txt
            // Android: billing_*.txt
            if (lowerName.includes('purchase_log_') || lowerName.includes('billing_')) {
                promises.push(
                    zipEntry.async('string').then(content => {
                        billingContents.push(content);
                    })
                );
                return;
            }

            // 2. Main Logs
            // iOS: inside logFiles/ folder and starts with log_
            // Android: root level (usually) or just .txt excluding billing
            const isIosLog = lowerName.includes('logfiles/') && lowerName.includes('log_');
            const isAndroidLog = !lowerName.includes('/') && (lowerName.endsWith('.txt') || lowerName.endsWith('.log')) && !lowerName.startsWith('billing');

            if (isIosLog || isAndroidLog) {
                promises.push(
                    zipEntry.async('string').then(content => {
                        // Extract date from filename for sorting if possible
                        // e.g., log_20231205.txt
                        // Simple heuristic: latest file usually has larger number/date string
                        mainLogs.push({
                            fileName: name.split('/').pop() || name, // Show only filename
                            content: content,
                            // Store original name for sorting heuristic
                        });
                    })
                );
            }
        });

        await Promise.all(promises);

        if (mainLogs.length > 0) {
            // Sort logs by name descending (assuming date is in filename: log_2025... > log_2024...)
            mainLogs.sort((a, b) => b.fileName.localeCompare(a.fileName));

            setCachedMainLogs(mainLogs);
            setCachedBillingContent(billingContents.join('\n'));

            // Parse the latest log (index 0)
            const latestLog = mainLogs[0];
            setLoadingMessage(`${latestLog.fileName} (최신) 분석 중...`);

            processContent(latestLog.content, latestLog.fileName, billingContents.join('\n'), mainLogs);
        } else {
            alert("ZIP 파일 내에서 분석 가능한 로그 파일(iOS: logFiles/log_*, Android: *.txt)을 찾을 수 없습니다.");
            setIsLoading(false);
        }

      } catch (e) {
        console.error(e);
        alert("ZIP 파일 압축 해제 실패. 올바른 파일인지 확인해주세요.");
        setIsLoading(false);
      }
    } else {
      // Normal text file
      const reader = new FileReader();
      reader.onload = (e) => {
        const text = e.target?.result;
        if (typeof text === 'string') {
          // Single file mode
          const singleFileCtx = [{ fileName: file.name, content: text }];
          setCachedMainLogs(singleFileCtx);
          setCachedBillingContent('');
          processContent(text, file.name, '', singleFileCtx);
        }
      };
      reader.readAsText(file);
    }
  };

  const handleReset = () => {
    setData(null);
    setCachedMainLogs([]);
    setCachedBillingContent('');
  };

  if (isLoading) {
    return (
      <div className="flex items-center justify-center min-h-screen bg-slate-50">
        <div className="flex flex-col items-center gap-4">
          <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
          <p className="text-slate-600 font-medium">{loadingMessage}</p>
        </div>
      </div>
    );
  }

  if (data) {
    return <Dashboard data={data} onReset={handleReset} onFileSelect={handleFileSelect} />;
  }

  return <FileUpload onFileLoaded={handleFile} />;
}

export default App;

import React, { useState } from 'react';
import { LifecycleEvent } from '../types';
import { Smartphone, Link, Unplug, Activity, Radio, Filter, CheckCircle2, Rocket, Settings, Search } from 'lucide-react';

interface EventTimelineProps {
  events: LifecycleEvent[];
}

export const EventTimeline: React.FC<EventTimelineProps> = ({ events }) => {
  const [showAllProtocols, setShowAllProtocols] = useState(false);

  if (events.length === 0) {
    return (
      <div className="p-8 text-center text-slate-500">
        감지된 주요 이벤트(화면 전환, 연결 등)가 없습니다.
      </div>
    );
  }

  const connectionEvents = events.filter(e => e.type === 'CONNECTION');
  const screenEvents = events.filter(e => e.type === 'SCREEN' || e.type === 'APP_STATE');

  // Filter connection events based on state
  const filteredConnectionEvents = connectionEvents.filter(evt => {
      // 1. Always show these critical events regardless of filter
      if (evt.message.includes('실시간 데이터')) return true;
      if (evt.message.includes('프로토콜 설정 (ATSP)')) return true;
      if (evt.message.includes('프로토콜 조회 (ATDPN)')) return true;
      if (evt.message.includes('연결 종료')) return true;
      if (evt.message.includes('연결 실패')) return true;
      if (evt.message.includes('연결 성공')) return true;
      if (evt.message.includes('LV RESET')) return true;

      // 2. If filter is active (Show All), show everything
      if (showAllProtocols) return true;

      // 3. In Default view, show only key connection steps
      if (evt.message.includes('초기화')) return true; // 0100 Init or BUS INIT
      if (evt.message.includes('프로토콜 감지')) return true;

      // Hide generic responses (OK, etc) in default view
      return false;
  });

  const getIcon = (type: LifecycleEvent['type'], message: string) => {
    if (type === 'SCREEN') return <Smartphone className="w-4 h-4 text-blue-500" />;
    if (type === 'APP_STATE') return <Activity className="w-4 h-4 text-purple-500" />;

    if (type === 'CONNECTION') {
      if (message.includes('실시간 데이터')) return <Rocket className="w-4 h-4 text-indigo-600" />;
      if (message.includes('프로토콜 설정')) return <Settings className="w-4 h-4 text-orange-600" />;
      if (message.includes('프로토콜 조회')) return <Search className="w-4 h-4 text-slate-600" />;

      if (message.includes('종료') || message.includes('실패')) return <Unplug className="w-4 h-4 text-red-500" />;
      if (message.includes('응답')) return <CheckCircle2 className="w-4 h-4 text-teal-500" />; // Response
      if (message.includes('프로토콜')) return <Radio className="w-4 h-4 text-orange-500" />; // Generic Protocol
      if (message.includes('LV RESET')) return <Activity className="w-4 h-4 text-red-600 animate-pulse" />;
      return <Link className="w-4 h-4 text-green-500" />;
    }
    return <Activity className="w-4 h-4 text-slate-500" />;
  };

  const TimelineList = ({ 
      title, 
      items, 
      emptyMessage, 
      hasFilter, 
      onToggleFilter, 
      isFilterActive 
  }: { 
      title: string, 
      items: LifecycleEvent[], 
      emptyMessage: string, 
      hasFilter?: boolean, 
      onToggleFilter?: () => void, 
      isFilterActive?: boolean 
  }) => (
    <div className="bg-white rounded-lg border border-slate-200 shadow-sm overflow-hidden flex flex-col h-[600px]">
      <div className="p-4 bg-slate-50 border-b border-slate-200 font-semibold text-slate-700 flex items-center justify-between shrink-0">
        <div className="flex items-center gap-2">
            <span>{title}</span>
        </div>
        <div className="flex items-center gap-3">
             {hasFilter && (
                <button 
                    onClick={onToggleFilter}
                    className={`p-1.5 rounded hover:bg-slate-200 transition-colors ${isFilterActive ? 'bg-blue-100 text-blue-600' : 'text-slate-400'}`}
                    title={isFilterActive ? "전체 프로토콜 보기" : "주요 이벤트만 보기"}
                >
                    <Filter className="w-4 h-4" />
                </button>
            )}
            <span className="text-xs font-normal text-slate-500">{items.length}개</span>
        </div>
      </div>
      <div className="flex-1 overflow-y-auto custom-scrollbar p-4 pb-20">
        {items.length === 0 ? (
          <div className="text-center text-slate-400 text-sm mt-10">{emptyMessage}</div>
        ) : (
          <div className="relative border-l-2 border-slate-200 ml-3 space-y-6">
            {items.map((evt) => (
              <div key={evt.id} className="relative pl-6">
                <div className="absolute -left-[9px] top-0 bg-white p-1 rounded-full border border-slate-200">
                  {getIcon(evt.type, evt.message)}
                </div>
                <div className="flex flex-col gap-1">
                  <span className="text-xs font-mono text-slate-400">
                    {evt.rawTimestamp.split(' ')[1] || evt.rawTimestamp}
                  </span>
                  <div className="flex-1">
                    <p className={`text-sm font-medium ${
                      evt.type === 'CONNECTION' ? 'text-slate-900' : 'text-slate-700'
                    }`}>
                      {evt.message}
                    </p>

                    {/* Special styling for protocol details */}
                    {evt.type === 'CONNECTION' && (evt.message.includes('프로토콜') || evt.message.includes('실시간')) ? (
                        <div className={`mt-1 border rounded px-2 py-1.5 text-xs font-mono break-all ${
                            evt.message.includes('응답') || evt.message.includes('실시간')
                            ? 'bg-teal-50 border-teal-100 text-teal-800' // Response Style
                            : 'bg-orange-50 border-orange-100 text-orange-800' // Request Style
                        }`}>
                             {evt.details}
                        </div>
                    ) : (
                        <p className="text-xs text-slate-400 mt-0.5 font-mono break-all line-clamp-2 hover:line-clamp-none">
                            {evt.details}
                        </p>
                    )}
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-6 pb-12">
      <TimelineList 
        title="🔌 연결 및 프로토콜 이력" 
        items={filteredConnectionEvents} 
        emptyMessage="연결 관련 이벤트가 없습니다."
        hasFilter={true}
        isFilterActive={showAllProtocols}
        onToggleFilter={() => setShowAllProtocols(!showAllProtocols)}
      />
      <TimelineList 
        title="📱 화면 및 앱 상태 이력" 
        items={screenEvents} 
        emptyMessage="화면 이동 내역이 없습니다." 
      />
    </div>
  );
};

