import { ParsedData, LogCategory } from '../types';

export interface AiAnalysisResult {
  analysis: string; // Technical analysis of the logs
  csResponse: string; // Suggested message to the customer
}

export const generateAiDiagnosis = async (data: ParsedData): Promise<AiAnalysisResult> => {
  const { metadata, logs, diagnosis } = data;

  // Retrieve OpenAI Key
  const apiKey = (process.env as any).OPENAI_API_KEY;

  if (!apiKey || apiKey === "YOUR_OPENAI_KEY_HERE") {
    throw new Error("OpenAI API Key가 설정되지 않았습니다. vite.config.ts 또는 .env 파일을 확인해주세요.");
  }

  // 1. Prepare Data Summary for the Prompt
  const errorLogs = logs
    .filter(l => l.category === LogCategory.ERROR)
    .slice(-15)
    .map(l => `[${l.rawTimestamp}] ${l.message}`)
    .join('\n');

  const initLogs = logs
    .slice(0, 10)
    .map(l => `[${l.rawTimestamp}] ${l.message}`)
    .join('\n');

  // 2. Construct the Prompt
  const systemPrompt = `You are a Senior Technical Support Engineer for the "Infocar OBD2 Scanner" app.
Your goal is to analyze log summaries and provide technical insights and a draft response for customer support.
Output must be a valid JSON object with keys: "analysis" and "csResponse".`;

  const userPrompt = `
--- SESSION METADATA ---
Device: ${metadata.model} (${metadata.userOS})
Car: ${metadata.carName} (Fuel: ${metadata.carInfo['carFuelType'] || 'Unknown'})
App Version: ${metadata.appVersion}
Country: ${metadata.countryCode || 'Unknown'}

--- DIAGNOSIS SUMMARY ---
Status: ${diagnosis.status}
Detected Issues: ${diagnosis.issues.join(', ') || 'None'}
Diagnosis Type: ${diagnosis.csType}

--- LOG SNIPPETS ---
[Initialization Phase]
${initLogs}

[Recent Errors]
${errorLogs || 'No explicit error logs found.'}

--- TASK ---
1. Technical Analysis: Briefly explain the technical root cause (e.g., Protocol mismatch, Bluetooth interference).
2. CS Response: Draft a polite, helpful customer service response in the language appropriate for Country (${metadata.countryCode || 'English'}).
   - Suggest specific steps (e.g., change protocol, check permissions).

Return ONLY the JSON.
`;

  try {
    // 3. Call OpenAI API
    const response = await fetch("https://api.openai.com/v1/chat/completions", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "Authorization": `Bearer ${apiKey}`
      },
      body: JSON.stringify({
        model: "gpt-4o", // Using gpt-4o as default for high quality
        messages: [
          { role: "system", content: systemPrompt },
          { role: "user", content: userPrompt }
        ],
        response_format: { type: "json_object" }
      })
    });

    if (!response.ok) {
      const errData = await response.json();
      throw new Error(errData.error?.message || "OpenAI API request failed");
    }

    const json = await response.json();
    const content = json.choices[0].message.content;

    if (!content) {
      throw new Error("No content received from OpenAI");
    }

    const result = JSON.parse(content) as AiAnalysisResult;
    return result;

  } catch (error) {
    console.error("AI Analysis Failed:", error);
    throw error;
  }
};

