                {diagnosis.issues.length > 0 ? (
                    <div className="bg-slate-50 rounded-md p-4 border border-slate-200">
                    <p className="text-xs font-semibold text-slate-500 mb-3 uppercase">감지된 이슈 사항</p>
                    <ul className="space-y-2">
                        {diagnosis.issues.map((issue, idx) => (
                        <li key={idx} className="flex items-start text-sm text-slate-700 gap-2">
                            <span className="mt-2 w-1.5 h-1.5 bg-slate-400 rounded-full shrink-0" />
                            {issue}
                        </li>
                        ))}
                    </ul>
                    </div>
                ) : (
                    <div className="text-sm text-slate-500">
                        특이 사항이 발견되지 않았습니다.
                    </div>
                )}
                </div>
            </div>
        </div>

        {/* Right Column: CS Response Generator */}
        <div className="flex flex-col">
            {/* 1. Template Section */}
            <div className="p-6 bg-slate-50/50 flex-1">
                <div className="flex items-center justify-between mb-4">
                     <div className="flex items-center gap-2">
                        <MessageSquare className="w-5 h-5 text-indigo-600" />
                        <h3 className="text-base font-bold text-slate-900">CS 템플릿 답변</h3>
                     </div>
                     <div className="flex items-center gap-2">
                        <div className="flex items-center gap-1 text-[10px] bg-white border border-slate-200 px-2 py-1 rounded-full text-slate-500">
                             <Globe className="w-3 h-3" />
                             <span>{languageName}</span>
                        </div>
                        {csText && (
                            <button 
                                onClick={() => handleCopy(csText)}
                                className="flex items-center gap-1.5 px-3 py-1.5 rounded-md text-xs font-bold bg-white text-slate-700 border border-slate-300 hover:bg-slate-50 hover:text-indigo-600 transition-all shadow-sm"
                            >
                                <Copy className="w-3 h-3" /> 복사
                            </button>
                        )}
                     </div>
                </div>

                <div className="flex-1">
                    {csText ? (
                         <div dir="auto" className={`w-full min-h-[100px] bg-white border border-slate-200 rounded-lg p-3 text-xs text-slate-700 font-mono whitespace-pre-wrap ${isRTL ? 'text-right' : 'text-left'}`}>
                            {csText}
                         </div>
                    ) : (
                        <div className="w-full min-h-[100px] flex flex-col items-center justify-center text-slate-400 border border-dashed border-slate-300 rounded-lg bg-slate-50">
                            <p className="text-sm">매칭되는 템플릿이 없습니다.</p>
                        </div>
                    )}
                </div>
            </div>

            {/* 2. AI Analysis Section */}
            <div className="p-6 border-t border-slate-200 bg-emerald-50/30">
                 <div className="flex items-center justify-between mb-4">
                     <div className="flex items-center gap-2">
                        <Sparkles className="w-5 h-5 text-emerald-600" />
                        <h3 className="text-base font-bold text-slate-900">AI 스마트 분석 (ChatGPT)</h3>
                     </div>
                     {!aiResult && !aiLoading && (
                        <button 
                            onClick={handleAiAnalysis}
                            className="flex items-center gap-1.5 px-4 py-2 rounded-md text-xs font-bold bg-emerald-600 text-white hover:bg-emerald-700 transition-all shadow-sm"
                        >
                            <Sparkles className="w-3 h-3" /> 분석 실행하기
                        </button>
                     )}
                </div>

                {aiLoading && (
                    <div className="flex items-center justify-center p-8 bg-white border border-slate-200 rounded-lg">
                        <RefreshCw className="w-6 h-6 text-emerald-600 animate-spin mr-2" />
                        <span className="text-sm text-slate-600 font-medium">ChatGPT(GPT-4o)가 로그를 분석 중입니다...</span>
                    </div>
                )}

                {aiError && (
                     <div className="p-4 bg-red-50 border border-red-200 rounded-lg flex items-center gap-2 text-sm text-red-700">
                        <AlertTriangle className="w-4 h-4" /> {aiError}
                     </div>
                )}

                {aiResult && (
                    <div className="space-y-4 animate-in fade-in slide-in-from-bottom-2 duration-500">
                        {/* Technical Analysis */}
                        <div className="bg-white p-4 rounded-lg border border-emerald-100 shadow-sm">
                             <h4 className="text-xs font-bold text-emerald-800 uppercase mb-2">Technical Insight</h4>
                             <p className="text-sm text-slate-700 leading-relaxed whitespace-pre-wrap">{aiResult.analysis}</p>
                        </div>

                        {/* Suggested Response */}
                        <div className="relative bg-white p-4 rounded-lg border border-emerald-100 shadow-sm">
                             <div className="flex items-center justify-between mb-2">
                                <h4 className="text-xs font-bold text-emerald-800 uppercase">Suggested Response</h4>
                                <button 
                                    onClick={() => handleCopy(aiResult.csResponse)}
                                    className="text-xs text-emerald-600 hover:text-emerald-800 font-medium flex items-center gap-1"
                                >
                                    {copied ? <Check className="w-3 h-3" /> : <Copy className="w-3 h-3" />} {copied ? '복사됨' : '복사'}
                                </button>
                             </div>
                             <p dir="auto" className="text-sm text-slate-700 leading-relaxed whitespace-pre-wrap font-mono bg-slate-50 p-3 rounded border border-slate-100">
                                {aiResult.csResponse}
                             </p>
                        </div>
                    </div>
                )}
            </div>
        </div>

      </div>
    </div>
  );
};

