                {aiResult && (
                    <div className="space-y-4 animate-in fade-in slide-in-from-bottom-2 duration-500">
                        {/* Technical Analysis */}
                        <div className="bg-white p-4 rounded-lg border border-purple-100 shadow-sm">
                             <h4 className="text-xs font-bold text-purple-800 uppercase mb-2">Technical Insight</h4>
                             <p className="text-sm text-slate-700 leading-relaxed whitespace-pre-wrap">{aiResult.analysis}</p>
                        </div>

                        {/* Suggested Response */}
                        <div className="relative bg-white p-4 rounded-lg border border-purple-100 shadow-sm">
