                                    {copied ? <Check className="w-3 h-3" /> : <Copy className="w-3 h-3" />} {copied ? '복사됨' : '복사'}
                                </button>
                             </div>
                             <p dir="auto" className="text-sm text-slate-700 leading-relaxed whitespace-pre-wrap font-mono bg-slate-50 p-3 rounded border border-slate-100">
                                {aiResult.csResponse}
                             </p>
                        </div>
                    </div>
                )}
            </div>
        </div>

      </div>
    </div>
  );
};

import { GoogleGenAI } from "@google/genai";
import { ParsedData, LogCategory } from '../types';

// Initialize the Gemini AI client
// The API key is obtained from the environment variable process.env.API_KEY
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export interface AiAnalysisResult {
  analysis: string; // Technical analysis of the logs
  csResponse: string; // Suggested message to the customer
}

export const generateAiDiagnosis = async (data: ParsedData): Promise<AiAnalysisResult> => {
  const { metadata, logs, diagnosis } = data;

  // 1. Prepare Data Summary for the Prompt
  // We cannot send the entire log file due to token limits, so we extract key information.

  // Extract recent error logs (last 15 errors)
  const errorLogs = logs
    .filter(l => l.category === LogCategory.ERROR)
    .slice(-15)
    .map(l => `[${l.rawTimestamp}] ${l.message}`)
    .join('\n');

  // Extract initialization logs (first 10 logs to see protocol setup)
  const initLogs = logs
    .slice(0, 10)
    .map(l => `[${l.rawTimestamp}] ${l.message}`)
    .join('\n');

  // 2. Construct the Prompt
  const prompt = `
Act as a Senior Technical Support Engineer for the "Infocar OBD2 Scanner" app.
Analyze the following log summary and provide a response.

--- CONTEXT ---
User is experiencing connection or functionality issues with the OBD2 scanner.
We need to analyze the logs to find the root cause (e.g., Protocol mismatch, Hardware interference, Bluetooth permission, Low voltage).

--- SESSION METADATA ---
Device: ${metadata.model} (${metadata.userOS})
Car: ${metadata.carName} (Fuel: ${metadata.carInfo['carFuelType'] || 'Unknown'})
App Version: ${metadata.appVersion}
Country: ${metadata.countryCode || 'Unknown'}

--- DIAGNOSIS SUMMARY (Rule-based) ---
Status: ${diagnosis.status}
Detected Issues: ${diagnosis.issues.join(', ') || 'None detected by rules'}
Diagnosis Type: ${diagnosis.csType}

--- LOG SNIPPETS ---
[Initialization Phase]
${initLogs}

[Recent Errors]
${errorLogs || 'No explicit error logs found.'}

--- TASK ---
1. Technical Analysis: Briefly explain what is happening technically based on the logs. Mention specific error codes or patterns if visible.
2. CS Response: Draft a polite, helpful customer service response in the language appropriate for the Country Code (${metadata.countryCode || 'English'}). 
   - If Country is KR, use Korean. If US/GB, use English. If JP, use Japanese, etc.
   - Suggest specific steps to fix the issue (e.g., change protocol, check Bluetooth permissions, unplug other devices).

Return the output in JSON format with two keys: "analysis" (Technical explanation) and "csResponse" ( The draft message for the user).
`;

  try {
    // 3. Call Gemini API
    // Explicitly using gemini-2.5-flash as requested
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
      },
    });

    const responseText = response.text;
    if (!responseText) {
      throw new Error("No response from AI");
    }

    const result = JSON.parse(responseText) as AiAnalysisResult;
    return result;

  } catch (error) {
    console.error("AI Analysis Failed:", error);
    throw error;
  }
};

