          </div>
        )}
        {!isConnecting && !isConnected && (
          <div className="flex items-center gap-2">
            <AlertTriangle className="w-4 h-4 text-red-500" />
            <span className="text-sm text-red-500">{t('disconnected')}</span>
          </div>
        )}
      </div>
      <div className="flex gap-1 items-center">
        {url && (
          <>
            <span className="text-xs truncate max-w-[200px]">{url}</span>
            <button onClick={onCopyClick}>
              <Copy className="w-4 h-4 text-gray-500 hover:text-gray-700" />
            </button>
          </>
        )}

        {isCustomUrl && onEdit && (
          <button onClick={onEdit} className="focus:outline-none">
            <Edit3 className="w-4 h-4 text-gray-500 hover:text-gray-700" />
          </button>
        )}

        {onRefresh && (
          <button onClick={onRefresh} className="focus:outline-none">
            <RefreshCw className="w-4 h-4 text-gray-500 hover:text-gray-700" />
          </button>
        )}
      </div>
      {copied && (
        <span className="text-xs text-gray-500">
          {t('copied')}
        </span>
      )}
    </div>
  );
};

export default ConnectionStatus;
