const getLanguageFromCountry = (countryCode: string | undefined): LanguageCode => {
  if (!countryCode) return 'EN';
  const code = countryCode.toUpperCase().trim();
  if (['KR', 'KOR', '82'].includes(code)) return 'KO';
  return 'EN'; 
};

export const ConnectionStatus: React.FC<ConnectionStatusProps> = ({ diagnosis, metadata, fullData }) => {
  const [copiedMap, setCopiedMap] = useState<Record<string, boolean>>({});
  const [aiLoading, setAiLoading] = useState(false);
  const [aiResult, setAiResult] = useState<AiAnalysisResult | null>(null);
  const [aiError, setAiError] = useState<string | null>(null);
  const [userContext, setUserContext] = useState<string>('');

  // Determine Language Template based on Country Code
  const { csText, languageName, langCode } = useMemo(() => {
    const code = getLanguageFromCountry(metadata.countryCode);
    const templateGroup = CS_TEMPLATES[code] || CS_TEMPLATES['EN']; // Fallback

    return {
      csText: templateGroup[diagnosis.csType] || '',
      languageName: LANGUAGE_NAMES[code] || 'English',
      langCode: code
    };
  }, [metadata.countryCode, diagnosis.csType]);

  const handleCopy = (text: string, id: string) => {
    if (!text) return;
    navigator.clipboard.writeText(text);
    setCopiedMap(prev => ({ ...prev, [id]: true }));
    setTimeout(() => setCopiedMap(prev => ({ ...prev, [id]: false })), 2000);
  };

  const handleAiAnalysis = async () => {
    if (!fullData) return;

    // Check for API Key Selection (Google AI Studio / IDX Environment)
    if (typeof window !== 'undefined' && (window as any).aistudio) {
        const aistudio = (window as any).aistudio;
        try {
            const hasKey = await aistudio.hasSelectedApiKey();
            if (!hasKey) {
                await aistudio.openSelectKey();
            }
        } catch (e) {
            console.warn("API Key selection check failed", e);
        }
    }

    setAiLoading(true);
    setAiError(null);
    try {
        const result = await generateAiDiagnosis(fullData, userContext);
        setAiResult(result);
    } catch (err: any) {
        console.error(err);
        let errorMsg = 'AI 분석에 실패했습니다.';

        // 1. Missing Key (Empty string from vite config)
        if (!process.env.API_KEY || (err.message && err.message.includes('API key not valid'))) {
             errorMsg = 'API Key가 설정되지 않았거나 유효하지 않습니다. 배포 환경(Vercel 등)의 환경 변수(API_KEY)를 확인해주세요.';
        }
        // 2. Specific handling for API Key errors (Expired, Not Found, Revoked)
        else if (err.message?.includes('Requested entity was not found') || err.message?.includes('API key') || err.message?.includes('400')) {
             // If in AI Studio/IDX environment, suggest re-selecting
             if (typeof window !== 'undefined' && (window as any).aistudio) {
                 errorMsg = 'API 키가 유효하지 않습니다. (잠시 후 키 선택창이 다시 열립니다)';
                 setTimeout(() => {
                    (window as any).aistudio.openSelectKey().catch(() => {});
                 }, 1000);
             } else {
                 // For standard Vercel/Netlify deployments
                 errorMsg = '설정된 API 키가 유효하지 않거나 만료되었습니다. 배포 설정의 API_KEY 변수를 확인해주세요.';
             }
        } else {
            errorMsg += ' (잠시 후 다시 시도해주세요)';
        }

        setAiError(errorMsg);
    } finally {
        setAiLoading(false);
    }
  };

  const isRTL = langCode === 'AR' || langCode === 'FA';

  return (
    <div className="bg-white rounded-lg border border-slate-200 mb-6 shadow-sm overflow-hidden">
      <div className="grid grid-cols-1 md:grid-cols-2 divide-y md:divide-y-0 md:divide-x divide-slate-200">

        {/* Left Column: Technical Diagnosis */}
        <div className="p-6">
            <div className="flex items-start gap-4 h-full">
