        timeGroups[t] = { time: p.timeStr, unix: t };
      }
      timeGroups[t][p.name] = p.value;
    });
    return Object.values(timeGroups).sort((a, b) => a.unix - b.unix);
  }, [series]);

  const avgDelay = useMemo(() => {
