import React, { useMemo } from 'react';
import { ObdDataPoint, ObdMetric } from '../types';
import { 
  LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, 
  ResponsiveContainer, Legend, Brush, AreaChart, Area 
} from 'recharts';
import { Gauge, Zap, Thermometer, Activity, Timer, AlertCircle, Info } from 'lucide-react';

interface ObdDashboardProps {
  series: ObdDataPoint[];
  metrics: Record<string, ObdMetric>;
}

const MetricCard = ({ metric, icon }: { metric: ObdMetric; icon: React.ReactNode }) => (
  <div className={`bg-white p-5 rounded-xl border ${metric.isAvailable ? 'border-slate-200' : 'border-slate-100 opacity-60'} shadow-sm transition-all hover:shadow-md`}>
    <div className="flex justify-between items-start mb-3">
      <div className="p-2 bg-slate-50 rounded-lg">{icon}</div>
      <span className={`text-[10px] font-bold px-2 py-1 rounded-full ${metric.isAvailable ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-100 text-slate-400'}`}>
        {metric.isAvailable ? 'ACTIVE' : 'NO DATA'}
      </span>
    </div>
    <div className="flex flex-col">
      <h4 className="text-xs font-semibold text-slate-500 uppercase tracking-tight">{metric.name}</h4>
      <div className="flex items-baseline gap-1 mt-1">
        <span className="text-2xl font-black text-slate-900">{metric.isAvailable ? metric.currentValue : '--'}</span>
        <span className="text-xs font-bold text-slate-400">{metric.unit}</span>
      </div>
    </div>
  </div>
);

export const ObdDashboard: React.FC<ObdDashboardProps> = ({ series, metrics }) => {
  // Chart Data Preparation
  const chartData = useMemo(() => {
    const timeGroups: Record<number, any> = {};
    series.forEach(p => {
      const t = Math.floor(p.unix / 1000) * 1000; // 1-second resolution
      if (!timeGroups[t]) {
        timeGroups[t] = { time: p.timeStr, unix: t };
      }
      timeGroups[t][p.name] = p.value;
    });
    return Object.values(timeGroups).sort((a, b) => a.unix - b.unix);
  }, [series]);

  const avgDelay = useMemo(() => {
    if (series.length === 0) return 0;
    return Math.round(series.reduce((acc, curr) => acc + curr.delay, 0) / series.length);
  }, [series]);

  return (
    <div className="space-y-6 pb-12">
      {/* Real-time Status Row */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <MetricCard metric={metrics['0C']} icon={<Activity className="w-5 h-5 text-indigo-500" />} />
        <MetricCard metric={metrics['0D']} icon={<Zap className="w-5 h-5 text-amber-500" />} />
        <MetricCard metric={metrics['05']} icon={<Thermometer className="w-5 h-5 text-red-500" />} />
        <MetricCard metric={metrics['04']} icon={<Gauge className="w-5 h-5 text-blue-500" />} />
      </div>

      {/* Main Analysis Area */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Multi-series Chart */}
        <div className="lg:col-span-2 bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
          <div className="flex items-center justify-between mb-6">
            <h3 className="font-bold text-slate-900 flex items-center gap-2">
              <Activity className="w-5 h-5 text-indigo-600" /> 주행 트렌드 분석
            </h3>
            <div className="text-xs text-slate-400 flex items-center gap-4">
               <span className="flex items-center gap-1"><Timer className="w-3 h-3" /> Avg Delay: {avgDelay}ms</span>
            </div>
          </div>
          <div className="h-[400px]">
            <ResponsiveContainer width="100%" height="100%">
              <LineChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="time" fontSize={10} axisLine={false} tickLine={false} minTickGap={50} />
                <YAxis yAxisId="left" fontSize={10} axisLine={false} tickLine={false} />
                <YAxis yAxisId="right" orientation="right" fontSize={10} axisLine={false} tickLine={false} />
                <Tooltip 
                  contentStyle={{ backgroundColor: '#1e293b', border: 'none', borderRadius: '8px', color: '#fff' }}
                  itemStyle={{ fontSize: '12px', fontWeight: 'bold' }}
                />
                <Legend iconType="circle" />
                <Line yAxisId="left" type="monotone" dataKey="RPM" stroke="#6366f1" strokeWidth={3} dot={false} animationDuration={300} />
                <Line yAxisId="left" type="monotone" dataKey="Vehicle Speed" stroke="#f59e0b" strokeWidth={3} dot={false} animationDuration={300} />
                <Line yAxisId="right" type="monotone" dataKey="Engine Load" stroke="#3b82f6" strokeWidth={2} dot={false} strokeDasharray="5 5" />
                <Brush dataKey="time" height={30} stroke="#cbd5e1" />
              </LineChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* PID Support List */}
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm flex flex-col">
            <h3 className="font-bold text-slate-900 mb-4 flex items-center gap-2">
                <Info className="w-5 h-5 text-slate-400" /> 센서 가용성 목록
            </h3>
            <div className="flex-1 overflow-y-auto space-y-2 pr-2 custom-scrollbar">
                {/* Fixed: Added explicit type ObdMetric to map parameter 'm' to avoid TS 'unknown' errors */}
                {Object.values(metrics).map((m: ObdMetric) => (
                    <div key={m.id} className={`flex items-center justify-between p-3 rounded-lg border transition-colors ${m.isAvailable ? 'bg-emerald-50/50 border-emerald-100' : 'bg-slate-50 border-slate-100'}`}>
                        <div>
                            <p className="text-xs font-bold text-slate-700">{m.name}</p>
                            <p className="text-[10px] text-slate-400 font-mono">PID: 01 {m.id}</p>
                        </div>
                        {m.isAvailable ? (
                             <div className="text-right">
                                <span className="text-sm font-black text-emerald-600">{m.currentValue}</span>
                                <span className="text-[10px] ml-0.5 text-emerald-400 font-bold">{m.unit}</span>
                             </div>
                        ) : (
                             <AlertCircle className="w-4 h-4 text-slate-300" />
                        )}
                    </div>
                ))}
            </div>
        </div>
      </div>

      {/* Delay Analysis (Area Chart) */}
      <div className="bg-slate-900 p-6 rounded-xl shadow-inner overflow-hidden">
          <h3 className="text-slate-100 font-bold mb-4 flex items-center gap-2">
              <Timer className="w-5 h-5 text-indigo-400" /> 통신 품질 (응답 지연시간)
          </h3>
          <div className="h-[120px]">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={series.slice(-100)}>
                <defs>
                    <linearGradient id="colorDelay" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#818cf8" stopOpacity={0.8}/>
                        <stop offset="95%" stopColor="#818cf8" stopOpacity={0}/>
                    </linearGradient>
                </defs>
                <Area type="monotone" dataKey="delay" stroke="#818cf8" fillOpacity={1} fill="url(#colorDelay)" />
                <Tooltip labelStyle={{ color: '#000' }} />
              </AreaChart>
            </ResponsiveContainer>
          </div>
          <p className="text-[10px] text-slate-400 mt-2">지연 시간이 200ms를 초과할 경우 스캐너 연결성 또는 OBD 버스 부하를 확인해야 합니다.</p>
      </div>
    </div>
  );
};

